import{_ as a,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Fixing Import Mistakes","description":"","frontmatter":{},"headers":[],"relativePath":"imports/import-mistakes.md","filePath":"imports/import-mistakes.md"}'),i={name:"imports/import-mistakes.md"};function l(s,e,n,h,d,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="fixing-import-mistakes" tabindex="-1">Fixing Import Mistakes <a class="header-anchor" href="#fixing-import-mistakes" aria-label="Permalink to &quot;Fixing Import Mistakes&quot;">​</a></h1><p>This page is the calm decision guide for &quot;something about my import is wrong.&quot;</p><h2 id="if-one-row-is-wrong" tabindex="-1">If one row is wrong <a class="header-anchor" href="#if-one-row-is-wrong" aria-label="Permalink to &quot;If one row is wrong&quot;">​</a></h2><p>Edit the row on the review page.</p><p>Use this when:</p><ul><li>the name is slightly wrong</li><li>the score needs correction</li><li>the wrong player was matched</li></ul><p>See <a href="./review-rows.html">Review Import Rows</a>.</p><h2 id="if-one-row-should-not-be-used-at-all" tabindex="-1">If one row should not be used at all <a class="header-anchor" href="#if-one-row-should-not-be-used-at-all" aria-label="Permalink to &quot;If one row should not be used at all&quot;">​</a></h2><p>Ignore the row.</p><p>Use this when:</p><ul><li>the screenshot included junk text</li><li>the same player was detected twice</li><li>the row is clearly not part of the event you are saving</li></ul><h2 id="if-the-import-found-the-wrong-player" tabindex="-1">If the import found the wrong player <a class="header-anchor" href="#if-the-import-found-the-wrong-player" aria-label="Permalink to &quot;If the import found the wrong player&quot;">​</a></h2><p>Try <strong>Rematch</strong> first.</p><p>If that still looks wrong, edit the row or add the missing player before accepting.</p><h2 id="if-the-whole-ocr-pass-looks-bad" tabindex="-1">If the whole OCR pass looks bad <a class="header-anchor" href="#if-the-whole-ocr-pass-looks-bad" aria-label="Permalink to &quot;If the whole OCR pass looks bad&quot;">​</a></h2><p>Upload the screenshot again with a better provider or clearer image.</p><p>Today, that is the practical replacement for an in-place reprocess workflow.</p><h2 id="if-you-already-accepted-and-it-was-wrong" tabindex="-1">If you already accepted and it was wrong <a class="header-anchor" href="#if-you-already-accepted-and-it-was-wrong" aria-label="Permalink to &quot;If you already accepted and it was wrong&quot;">​</a></h2><p>Use <a href="./delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a> when you need to undo the tracked applied changes.</p><p>Then, if useful:</p><ul><li>restore the import as a draft</li><li>re-review it</li><li>re-accept only the correct rows</li></ul><h2 id="if-the-screenshot-context-was-wrong" tabindex="-1">If the screenshot context was wrong <a class="header-anchor" href="#if-the-screenshot-context-was-wrong" aria-label="Permalink to &quot;If the screenshot context was wrong&quot;">​</a></h2><p>Do not force the rows through. Start again with the correct:</p><ul><li>kingdom</li><li>alliance</li><li>event</li><li>date</li><li>stage or total mode</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./upload-screenshots.html">Upload Screenshots</a></li><li><a href="./delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a></li><li><a href="./restore-import.html">Restore a Deleted Import</a></li></ul>',26)])])}const f=a(i,[["render",l]]);export{m as __pageData,f as default};
